@module commandManager  src=commandManager.lua  loc=594  sha=7e24684  mode=chunk  self=cmgr
@deps cm

# Invariants & contracts
  @invariant  cmgr owns a flat command namespace; scopes own keymaps + modal/passthrough only  @ 3
  @invariant  scope:register installs a gated wrapper; invoke returns nil when scope is unreachable  @ 4
  @invariant  scopes form a stack walked top-down; the bottom is the 'global' scope pushed at module load  @ 5
  @invariant  a modal scope without passthrough[name] blocks both key dispatch and invoke for names below it  @ 6
  @invariant  command return: nil = handled (stop dispatch); false = declined (let char queue see the keypress)  @ 7
  @invariant  spring-loaded scope: redirect[] reinterprets; keepAlive[] passes; else onBail()  @ 8
  @invariant  a keymap entry is an array of keyspecs — multiple bindings dispatch to the same command  @ 9
  @invariant  layouts row 1 = base octave (15 semitones, C..D+1oct); row 2 = +1 octave (17 semitones, C..F+1oct)  @ 10
  @invariant  chars is folded from layouts at load time so the LUT can't drift from the declaration  @ 11
  @contract  optional undoDesc wraps fn in util.atomic(undoDesc, fn) so REAPER's undo stack records this command as a labelled block  @ 88
  @contract  registerAll value is either fn or {fn, undoDesc}; the tuple form opts the command into REAPER undo wrapping with the given label  @ 95

# Shapes
  @shape  keyspec = keyConstant | { keyConstant, mod1, mod2, ... }   -- mods OR'd into a single mask  @ 12
  @shape  keymapEntry = { keyspec, ... }                              -- array; each keyspec triggers the same command  @ 13
  @shape  noteChar = { semi = 0..16, octOff = 0..1 }  @ 14
  @shape  scope = { keymap={}, registered={}, modal?, passthrough?, springLoaded?, redirect={[name]=fn}?, keepAlive={[name]=true}?, onBail? }  @ 79

